from fastapi import Depends, HTTPException, status
from app.auth import get_current_user

PLAN_DAILY_TOKENS = {
    "free":       100_000,
    "pro":      2_000_000,
    "enterprise": None,   # unlimited (governed by contract)
}

QUOTA_WARNING_THRESHOLD = 0.80  # warn at 80%

async def check_quota(user_id: str, plan: str, estimated_tokens: int) -> None:
    limit = PLAN_DAILY_TOKENS.get(plan)
    if limit is None:
        return  # enterprise: no hard cap in Redis

    current = await get_usage(user_id)
    if current + estimated_tokens > limit:
        raise HTTPException(
            status_code=status.HTTP_429_TOO_MANY_REQUESTS,
            detail={
                "error": "quota_exceeded",
                "used": current,
                "limit": limit,
                "resets_at": time.strftime("%Y-%m-%dT00:00:00Z",
                                           time.gmtime(_midnight_timestamp())),
                "upgrade_url": "/billing/plans",
            },
            headers={
                "X-Quota-Limit": str(limit),
                "X-Quota-Used": str(current),
                "Retry-After": str(_midnight_timestamp() - int(time.time())),
            },
        )

def quota_warning_header(used: int, limit: int | None) -> dict[str, str]:
    if limit is None or used / limit < QUOTA_WARNING_THRESHOLD:
        return {}
    return {"X-Quota-Warning": f"{used/limit:.0%} of daily token quota consumed"}

def _month_key(user_id: str, quota_type: str) -> str:
    month = time.strftime("%Y-%m", time.gmtime())
    return f"quota:{quota_type}:{user_id}:{month}"

def _end_of_month_timestamp() -> int:
    t = time.gmtime()
    # First second of next month
    if t.tm_mon == 12:
        next_month = time.struct_time((t.tm_year + 1, 1, 1, 0, 0, 0, 0, 0, 0))
    else:
        next_month = time.struct_time((t.tm_year, t.tm_mon + 1, 1, 0, 0, 0, 0, 0, 0))
    return int(time.mktime(next_month))

PLAN_MONTHLY_RAG_PAGES = {"free": 0, "pro": 500, "enterprise": 50_000}

async def check_rag_ingestion_quota(user_id: str, plan: str, page_count: int) -> None:
    limit = PLAN_MONTHLY_RAG_PAGES[plan]
    if limit == 0:
        raise HTTPException(403, "RAG ingestion not available on free plan")

    key = _month_key(user_id, "rag_pages")
    used = int(await redis.get(key) or 0)
    if used + page_count > limit:
        raise HTTPException(
            status.HTTP_429_TOO_MANY_REQUESTS,
            detail={"error": "monthly_rag_quota_exceeded", "used": used, "limit": limit},
        )
    async with redis.pipeline() as pipe:
        pipe.incrby(key, page_count)
        pipe.expireat(key, _end_of_month_timestamp())
        await pipe.execute()
